import{_ as t,o as a,c as o,a2 as d}from"./chunks/framework.IwO0Hdn_.js";const p=JSON.parse('{"title":"🏗️ Arquitectura y Riesgos — Log Management Dashboard","description":"","frontmatter":{},"headers":[],"relativePath":"2_architecture_risks.md","filePath":"2_architecture_risks.md","lastUpdated":null}'),r={name:"2_architecture_risks.md"};function i(n,e,s,c,l,g){return a(),o("div",null,[...e[0]||(e[0]=[d('<h1 id="🏗️-arquitectura-y-riesgos-—-log-management-dashboard" tabindex="-1">🏗️ Arquitectura y Riesgos — Log Management Dashboard <a class="header-anchor" href="#🏗️-arquitectura-y-riesgos-—-log-management-dashboard" aria-label="Permalink to &quot;🏗️ Arquitectura y Riesgos — Log Management Dashboard&quot;">​</a></h1><p><strong>Proyecto:</strong> Panel de Administración y Gestión de Logs Multi-Aplicación <strong>Fecha:</strong> 2026-03-03 <strong>Skill:</strong> System Architect — C4 Model + STRIDE + NFRs <strong>Estado:</strong> FASE 2 Completada</p><hr><h2 id="_1-requisitos-no-funcionales-nfrs" tabindex="-1">1. Requisitos No Funcionales (NFRs) <a class="header-anchor" href="#_1-requisitos-no-funcionales-nfrs" aria-label="Permalink to &quot;1. Requisitos No Funcionales (NFRs)&quot;">​</a></h2><h3 id="_1-1-escalabilidad" tabindex="-1">1.1 Escalabilidad <a class="header-anchor" href="#_1-1-escalabilidad" aria-label="Permalink to &quot;1.1 Escalabilidad&quot;">​</a></h3><table tabindex="0"><thead><tr><th>NFR</th><th>Descripción</th><th>Decisión</th></tr></thead><tbody><tr><td>NFR-ESC-01</td><td>Monocliente con un único usuario administrador. No se requiere escalado horizontal de frontend.</td><td>El backend se ejecuta como proceso único PHP-FPM (Laravel). Sin necesidad de balanceador de carga.</td></tr><tr><td>NFR-ESC-02</td><td>Volumen de logs: múltiples aplicaciones. Puede crecer a miles de registros por día.</td><td>PostgreSQL con índices en <code>(type, created_at, app_source)</code>. Paginación obligatoria en todas las queries.</td></tr><tr><td>NFR-ESC-03</td><td>El histórico es de escritura única y lectura frecuente.</td><td>Tabla <code>archived_logs</code> separada de <code>logs</code>. Sin TTL. Candidata a particionado por año si crece.</td></tr></tbody></table><h3 id="_1-2-disponibilidad-sla" tabindex="-1">1.2 Disponibilidad (SLA) <a class="header-anchor" href="#_1-2-disponibilidad-sla" aria-label="Permalink to &quot;1.2 Disponibilidad (SLA)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>NFR</th><th>Descripción</th><th>Decisión</th></tr></thead><tbody><tr><td>NFR-DIS-01</td><td>Sistema interno de administración. SLA objetivo: <strong>99.5%</strong> (uso en horario laboral).</td><td>No requiere configuración HA compleja. Un proceso de reinicio automático (systemd + PHP-FPM/Supervisor) es suficiente.</td></tr><tr><td>NFR-DIS-02</td><td>La caída del panel no afecta a la ingesta de logs (n8n → Postgres es independiente).</td><td>Desacoplamiento garantizado por diseño. Riesgo bajo.</td></tr></tbody></table><h3 id="_1-3-latencia" tabindex="-1">1.3 Latencia <a class="header-anchor" href="#_1-3-latencia" aria-label="Permalink to &quot;1.3 Latencia&quot;">​</a></h3><table tabindex="0"><thead><tr><th>NFR</th><th>Descripción</th><th>Decisión</th></tr></thead><tbody><tr><td>NFR-LAT-01</td><td>Dashboard debe cargar en &lt; 1 s. Las cards solo cuentan registros agrupados (queries agregadas).</td><td>Usar <code>COUNT(*) GROUP BY type</code> con índice. Cachear resultado en memoria por 5-10 s antes de broadcast SSE.</td></tr><tr><td>NFR-LAT-02</td><td>Listado tabular con filtros: respuesta &lt; 500 ms.</td><td>Índices compuestos en columnas de filtro. LIMIT/OFFSET o cursor-based pagination.</td></tr><tr><td>NFR-LAT-03</td><td>SSE: evento push en &lt; 2 s desde inserción en DB por n8n.</td><td>Polling interno ligero (1-2 s) sobre tabla <code>logs</code> o trigger NOTIFY/LISTEN de PostgreSQL.</td></tr></tbody></table><h3 id="_1-4-observabilidad" tabindex="-1">1.4 Observabilidad <a class="header-anchor" href="#_1-4-observabilidad" aria-label="Permalink to &quot;1.4 Observabilidad&quot;">​</a></h3><table tabindex="0"><thead><tr><th>NFR</th><th>Descripción</th><th>Decisión</th></tr></thead><tbody><tr><td>NFR-OBS-01</td><td>El propio sistema gestiona logs de otras apps; sus propios errores internos se escriben en fichero local.</td><td>Logs de aplicación en <code>/var/log/log-dashboard/app.log</code> con rotación. No se auto-reportan en Postgres para evitar recursión.</td></tr><tr><td>NFR-OBS-02</td><td>Auditoría de acciones del administrador (archivado, comentarios).</td><td>Campo <code>archived_by</code>, <code>archived_at</code>, <code>updated_at</code> en tabla <code>archived_logs</code>.</td></tr></tbody></table><hr><h2 id="_2-decisiones-tecnologicas-justificadas" tabindex="-1">2. Decisiones Tecnológicas Justificadas <a class="header-anchor" href="#_2-decisiones-tecnologicas-justificadas" aria-label="Permalink to &quot;2. Decisiones Tecnológicas Justificadas&quot;">​</a></h2><blockquote><p><strong>⚠️ Actualizado 2026-03-14:</strong> Stack cambiado de Laravel + React 19 (SPA) a <strong>Laravel 12 + Livewire 3</strong> (SSR reactivo). Sin SPA independiente.</p></blockquote><table tabindex="0"><thead><tr><th>Componente</th><th>Tecnología Elegida</th><th>Alternativa Descartada</th><th>Justificación</th></tr></thead><tbody><tr><td>Backend</td><td><strong>Laravel 12 (PHP)</strong></td><td>—</td><td>Framework maduro con ORM Eloquent. Controladores web clásicos. SSE via <code>StreamedResponse</code>.</td></tr><tr><td>Frontend dinámico</td><td><strong>Livewire 3</strong></td><td>React 19 + Vite, Vue 3</td><td>Componentes reactivos server-side sin necesidad de SPA ni build JS separado. Ideal para herramienta interna. Reduce complejidad operacional enormemente.</td></tr><tr><td>Microinteracciones</td><td><strong>Alpine.js</strong> (incluido con Livewire)</td><td>React hooks</td><td>Microinteracciones en cliente (modales, toggles). Sin bundle JS complejo.</td></tr><tr><td>Estructura proyecto</td><td><strong>Monolito Laravel: Blade + Livewire</strong></td><td>SPA separada, Inertia.js</td><td>Un único proceso, un despliegue. Sin CORS. Sin doble repositorio. Las vistas son Blade con componentes Livewire embebidos.</td></tr><tr><td>API Contract</td><td><strong>Livewire Actions (wire:click, wire:model)</strong></td><td>REST puro, GraphQL</td><td>Con Livewire no se necesita una REST API para el frontend. El SSE sigue siendo un endpoint HTTP independiente.</td></tr><tr><td>Tiempo real</td><td><strong>SSE via <code>StreamedResponse</code> de Laravel</strong></td><td>WebSockets (Reverb/Pusher)</td><td>Comunicación unidireccional (servidor → cliente). Compatible con Livewire: el cliente JS actualiza el componente al recibir el evento.</td></tr><tr><td>Rich Text Editor</td><td><strong>TipTap 2 + Alpine.js bridge</strong></td><td>Quill.js, CKEditor</td><td>TipTap es headless y funciona con Livewire mediante un componente Alpine que sincroniza el contenido con <code>wire:model</code>. Soporte de imágenes y formato enriquecido.</td></tr><tr><td>Base de datos</td><td><strong>PostgreSQL</strong> (existente)</td><td>—</td><td>Ya existe el flujo n8n → Postgres. Eloquent ORM soporta PostgreSQL de forma nativa.</td></tr><tr><td>Notificaciones DB</td><td><strong>pg_notify / LISTEN</strong> via worker Laravel</td><td>Polling puro</td><td>Reduce latencia SSE. Proceso Artisan Command gestionado por Supervisor.</td></tr><tr><td>Autenticación</td><td><strong>Sesión externa (API) + mock de sesión</strong></td><td>Laravel Sanctum SPA, Passport</td><td>La pantalla de Login queda FUERA del alcance. El usuario llega autenticado desde un sistema externo. En desarrollo se simula con un mock de usuario en sesión. No hay endpoint de login en este panel.</td></tr><tr><td>i18n</td><td><strong>Laravel Lang (resources/lang/)</strong></td><td>Stubs en blade</td><td>Textos UI en archivos de idioma. Soporte base para <code>es</code> y estructura preparada para <code>va</code>.</td></tr></tbody></table><hr><h2 id="_3-modelado-de-amenazas-—-stride" tabindex="-1">3. Modelado de Amenazas — STRIDE <a class="header-anchor" href="#_3-modelado-de-amenazas-—-stride" aria-label="Permalink to &quot;3. Modelado de Amenazas — STRIDE&quot;">​</a></h2><h3 id="componentes-criticos-analizados" tabindex="-1">Componentes críticos analizados <a class="header-anchor" href="#componentes-criticos-analizados" aria-label="Permalink to &quot;Componentes críticos analizados&quot;">​</a></h3><ol><li><strong>Backend Laravel</strong> (controladores + Livewire Actions + SSE)</li><li><strong>Base de Datos PostgreSQL</strong> (logs activos + histórico + error_codes)</li><li><strong>Frontend Blade/Livewire</strong> (panel admin, SSR)</li><li><strong>Editor Rich Text</strong> (comentarios con imágenes — TipTap 2 + Alpine.js)</li></ol><hr><h3 id="_3-1-componente-api-backend" tabindex="-1">3.1 Componente: API Backend <a class="header-anchor" href="#_3-1-componente-api-backend" aria-label="Permalink to &quot;3.1 Componente: API Backend&quot;">​</a></h3><table tabindex="0"><thead><tr><th>STRIDE</th><th>Amenaza</th><th>Riesgo</th><th>Mitigación</th></tr></thead><tbody><tr><td><strong>S</strong> Spoofing</td><td>Un agente externo suplanta al administrador y accede al panel.</td><td>ALTO</td><td>Autenticación con sesión firmada (JWT/cookie httpOnly). Aunque es un único usuario, se requiere login.</td></tr><tr><td><strong>T</strong> Tampering</td><td>Modificación de un log activo antes de archivarlo.</td><td>MEDIO</td><td>Los logs activos son solo lectura desde la API (solo n8n puede insertar). Endpoints de escritura solo para <code>archived_logs</code>.</td></tr><tr><td><strong>R</strong> Repudiation</td><td>No hay trazabilidad de quién archivó o comentó.</td><td>BAJO</td><td>Campos <code>archived_by</code> y <code>created_at</code> en todas las acciones de escritura.</td></tr><tr><td><strong>I</strong> Information Disclosure</td><td>Endpoint SSE expuesto sin autenticación filtra logs en tiempo real.</td><td>ALTO</td><td>El stream SSE debe requerir sesión válida antes de abrirse.</td></tr><tr><td><strong>D</strong> Denial of Service</td><td>Peticiones masivas al endpoint de listado con filtros pesados.</td><td>BAJO</td><td>Monocliente + red interna. Rate limiting básico como precaución.</td></tr><tr><td><strong>E</strong> Elevation of Privilege</td><td>No aplica (único rol administrador).</td><td>N/A</td><td>—</td></tr></tbody></table><hr><h3 id="_3-2-componente-base-de-datos-postgresql" tabindex="-1">3.2 Componente: Base de Datos PostgreSQL <a class="header-anchor" href="#_3-2-componente-base-de-datos-postgresql" aria-label="Permalink to &quot;3.2 Componente: Base de Datos PostgreSQL&quot;">​</a></h3><table tabindex="0"><thead><tr><th>STRIDE</th><th>Amenaza</th><th>Riesgo</th><th>Mitigación</th></tr></thead><tbody><tr><td><strong>S</strong> Spoofing</td><td>Otro servicio usa las credenciales de DB del panel.</td><td>MEDIO</td><td>Usuario de DB dedicado con permisos mínimos (SELECT en <code>logs</code>, CRUD en <code>archived_logs</code>).</td></tr><tr><td><strong>T</strong> Tampering</td><td>Borrado accidental o malicioso del histórico.</td><td>ALTO</td><td>El usuario de DB del panel no tiene permiso DELETE sobre <code>archived_logs</code>. Solo INSERT/UPDATE.</td></tr><tr><td><strong>R</strong> Repudiation</td><td>Sin log de cambios en DB.</td><td>BAJO</td><td>Timestamps en todas las tablas (<code>created_at</code>, <code>updated_at</code>).</td></tr><tr><td><strong>I</strong> Information Disclosure</td><td>Credenciales de DB en código fuente.</td><td>ALTO</td><td>Credenciales en variables de entorno (<code>.env</code>, nunca en repositorio).</td></tr><tr><td><strong>D</strong> Denial of Service</td><td>Query sin LIMIT satura la DB.</td><td>MEDIO</td><td>ORM/query builder con LIMIT máximo hardcoded (ej. 500 filas por petición).</td></tr><tr><td><strong>E</strong> Elevation of Privilege</td><td>Escalado de permisos vía SQL injection.</td><td>MEDIO</td><td>Uso exclusivo de queries parametrizadas / ORM. Nunca concatenar strings SQL.</td></tr></tbody></table><hr><h3 id="_3-3-componente-editor-rich-text-comentarios" tabindex="-1">3.3 Componente: Editor Rich Text (Comentarios) <a class="header-anchor" href="#_3-3-componente-editor-rich-text-comentarios" aria-label="Permalink to &quot;3.3 Componente: Editor Rich Text (Comentarios)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>STRIDE</th><th>Amenaza</th><th>Riesgo</th><th>Mitigación</th></tr></thead><tbody><tr><td><strong>S</strong> Spoofing</td><td>No aplica (editor local del admin).</td><td>N/A</td><td>—</td></tr><tr><td><strong>T</strong> Tampering</td><td>XSS embebido en HTML del comentario guardado.</td><td>ALTO</td><td>Sanitizar HTML en el backend antes de persistir (ej. <code>DOMPurify</code> server-side). Nunca renderizar HTML crudo sin sanitizar.</td></tr><tr><td><strong>R</strong> Repudiation</td><td>—</td><td>N/A</td><td>—</td></tr><tr><td><strong>I</strong> Information Disclosure</td><td>Imágenes subidas expuestas sin control.</td><td>MEDIO</td><td>Si las imágenes se suben a storage, requerir token de acceso firmado. Alternativa: almacenar como base64 en la propia entrada (más simple pero limita tamaño).</td></tr><tr><td><strong>D</strong> Denial of Service</td><td>Upload de imágenes enormes agota almacenamiento.</td><td>MEDIO</td><td>Límite de tamaño por upload (ej. 2 MB) y por comentario (ej. 10 MB total).</td></tr><tr><td><strong>E</strong> Elevation of Privilege</td><td>Archivo malicioso disfrazado de imagen.</td><td>MEDIO</td><td>Validar MIME type real (magic bytes) en el backend, no solo la extensión.</td></tr></tbody></table><hr><h2 id="_4-resumen-de-riesgos-por-severidad" tabindex="-1">4. Resumen de Riesgos por Severidad <a class="header-anchor" href="#_4-resumen-de-riesgos-por-severidad" aria-label="Permalink to &quot;4. Resumen de Riesgos por Severidad&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Severidad</th><th>Amenazas</th></tr></thead><tbody><tr><td>🔴 ALTO</td><td>SSE sin autenticación · Borrado de histórico · Credenciales en repo · XSS en comentarios</td></tr><tr><td>🟡 MEDIO</td><td>Suplantación de servicio DB · SQL Injection · Imágenes sin control · DoS por queries</td></tr><tr><td>🟢 BAJO</td><td>Repudio de acciones · DoS en red interna</td></tr></tbody></table><hr><h2 id="_5-restricciones-tecnicas-identificadas" tabindex="-1">5. Restricciones Técnicas Identificadas <a class="header-anchor" href="#_5-restricciones-tecnicas-identificadas" aria-label="Permalink to &quot;5. Restricciones Técnicas Identificadas&quot;">​</a></h2><ol><li><strong>La estructura de la tabla <code>logs</code> en Postgres ya existe</strong> — el schema se debe descubrir/documentar antes del desarrollo (campo <code>type</code>, campo <code>app_source</code>, campo <code>message</code>, timestamps).</li><li><strong>El flujo n8n no se modifica</strong> — la ingesta de logs es ajena al alcance de este proyecto.</li><li><strong>Sin pantalla de login en este panel</strong> — la autenticación viene de un sistema externo. Para desarrollo, mock de usuario en sesión Laravel.</li><li><strong>Sin despliegue cloud</strong> — la app corre en infraestructura local.</li><li><strong>Sin SPA / sin build Vite separado</strong> — el frontend es Blade + Livewire servido directamente por Laravel.</li><li><strong>Tabla <code>error_codes</code> es nueva</strong> — debe crearse con migración. Clave compuesta <code>(code + app_source)</code>. CRUD completo en este panel.</li><li><strong>Comentarios son exclusivos del Histórico y Error Codes</strong> — no aparecen en la vista de logs activos.</li><li><strong>Filtros → GET, Orden → POST</strong> — los filtros y página se pasan como query params en la URL (persistibles/compartibles). La ordenación de columnas se envía como formulario POST y no persiste en URL.</li></ol>',35)])])}const h=t(r,[["render",i]]);export{p as __pageData,h as default};
